<template>
    <view>
        <view class="top1">
            <view class="topLeft">
                カードの種類
            </view>
            <view class="topRight">
                <view class="pickers" @click="showPop">
                    <view class="pickerName" v-text='type == 1? "スタンプカード A" :  type == 2? "スタンプカード B" :"ポイントカード" '></view>
                    <u-icon name="arrow-down"></u-icon>
                </view>
            </view>
        </view>
        <view class="addNew" @click="addNew">
            <u-icon name="plus-circle-fill" color="#1A73E8" size="22"></u-icon>
            <text>カードを作る</text>
        </view>
        <view class="noData" v-if="array.length == 0">
            登録されたカードはありません
        </view> 
        <view class="cards">
            <u-swipe-action>
                <u-swipe-action-item :options="options" v-for="(item,index) in array" @click="deleteItem(item)">
                    <view class="swipe-action u-border-top u-border-bottom">
                        <view class="swipe-action__content">
                            <view class="listContent">
                                <view class="listItem">
                                    <view class="itemLeft">
                                        <view class="selectContent" @click="chooseItem(item.id)">
                                            <view class="unselect" v-if="!item.default"></view>
                                            <view class="selected" v-if="item.default">
                                                <view class="fill"></view>
                                            </view>
                                        </view>
                                    </view>
                                    <view class="itemRight">
                                        <view class="itemTitle" v-text="item.name"></view>
                                        <view class="items" v-if="type != 3" v-text="`スタンプ数 : ${item.count}個`"></view>
                                        <view class="items" v-if="item.valid_type == 1" v-text="`有効期限：発行から${item.valid_day}年`"></view>
                                        <view class="items" v-else v-text="`有効期限:${item.expire_time}`"></view>
                                        <view class="bk">
                                            <view>カード背景色</view>
                                            <view class="colorSqu" :style="`background:${item.background_color}`"></view>
                                        </view>
                                        <view class="itemImage">
                                            <image :src="item.image" mode=""></image>
                                        </view>
                                    </view>
                                </view>
                            </view>
                        </view>
                    </view>
                </u-swipe-action-item>
            </u-swipe-action>
        </view>
        <u-popup :show="show" round="32">
            <view class="pTitle">
                <view class="pClose">
                    <image src="../../../static/icons/tclose.png" mode="" @click="show=false"></image>
                </view>
                <view class="pTitlename">
                    カードの種類
                </view>
                <view class="pSave" @click="getList">
                    保存
                </view>
            </view>
            <view class="pContent">
                <view id="title">
                    カードの種類を選んでください
                </view>
                <view class="pItem">
                    <view class="itemTitle">
                        <view class="selectContent"  @click="changeType(1)">
                            <view class="unselect" v-if="type != 1"></view>
                            <view class="selected" v-if="type == 1">
                                <view class="fill"></view>
                            </view>
                        </view>
                        <view class="typeName">
                            スタンプカード A
                        </view>
                    </view>
                    <image class="pitemImage" src="../../../static/images/typeA.png" mode="widthFix"></image>
                </view>
                <view class="pItem">
                    <view class="itemTitle">
                        <view class="selectContent"  @click="changeType(2)">
                            <view class="unselect" v-if="type != 2"></view>
                            <view class="selected" v-if="type == 2">
                                <view class="fill"></view>
                            </view>
                        </view>
                        <view class="typeName">
                            スタンプカードB
                        </view>
                    </view>
                    <image class="pitemImage" src="../../../static/images/typeB.png" mode="widthFix"></image>
                    <view class="introduce">
                        <view class="inTitle">
                            [スタンプカードの特徴]
                        </view>
                        <view class="introContent">
                            <view>
                                ・スタンプでのポイント付与カード。
                            </view>
                            <view>
                                ・スタンプ満了数は3個〜30個まで設定できます。
                            </view>
                            <view>
                                ・１度に１〜９個までのスタンプ付与が可能。
                            </view>
                            <view>
                                ・カード枠の色は自由に設定できます。
                            </view>
                            <view>
                                ・付与した日付、担当者(設定任意)が表示されます。
                            </view>
                            <view>
                                ・スタンプデザインはテンプレートから選択またはPNG ファイルアップロードでオリジナルデザイン設定が可能。
                            </view>
                        </view>
                    </view>
                </view>
                <view class="pItem border_top" style="margin-top: 100upx;padding-top: 38upx;">
                    <view class="itemTitle">
                        <view class="selectContent" @click="changeType(3)">
                            <view class="unselect" v-if="type != 3"></view>
                            <view class="selected" v-if="type == 3">
                                <view class="fill"></view>
                            </view>
                        </view>
                        <view class="typeName">
                            ポイントカード
                        </view>
                    </view>
                    <image class="pitemImage" src="../../../static/images/typeC.png" mode="widthFix"></image>
                    <view class="introduce">
                        <view class="inTitle">
                            [ポイントカードの特徴]
                        </view>
                        <view class="introContent">
                            <view>
                                ・バーコードによるカード情報の読み込み。
                            </view>
                            <view>
                                ・利用金額に合わせたポイント付与が可能。
                            </view>
                            <view>
                                ・ポイント利用による増減もアプリからできます。
                            </view>
                            <view>
                                ・現在お使いの他社会員システムのバーコード情報の入力で、
                            </view>
                            <view>
                                　　　デジタル会員カードの作成が可能。
                            </view>
                            <view>
                                ・バーコード情報(番号)は編集できます。
                            </view>
                            <view>
                                ・ポイント付与無し、ポイント数の非表示設定ができます。
                            </view>
                        </view>
                    </view>
                </view>
            </view>
        </u-popup>
    </view>
</template>
<script>
    import {getCardList,setDefaultCard,deleteMembershipCard} from '@/api/index.js'
    export default {
        data() {
            return {
                select: "",
                show: false,
                type:1,
                options: [{
                    text: '削除',
                    style: {
                        backgroundColor: '#D93025'
                    }
                }],
                array: []
            }
        },
        created() {
            this.getList()
        },
        methods: {
            showPop() {
                let that = this
                that.show = true
            },
            addNew() {
                uni.navigateTo({
                    url: "firstStep/firstStep?type="+this.type
                })
            },
            changeType(e){
                let that = this
                that.type = e
                console.log(e)
            },
            
            chooseItem(id){
                let that = this 
                setDefaultCard(id).then((res) =>{
                    if(res.code == 200){
                        uni.showToast({
                            title:res.message
                        })
                        that.getList()
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
            },
            getList(){
                let that = this
                getCardList(that.type).then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        that.array = res.data.cards
                        that.show = false
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
            },
            deleteItem(e){
                let that = this
                deleteMembershipCard(e.id).then((res) => {
                    if(res.code == 200){
                        uni.showToast({
                            title:res.message
                        })
                        that.getList()
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
            }
        }
    }
</script>

<style lang="scss">
    .introduce {
        box-sizing: border-box;
        padding: 0 38upx;
        margin-top: 80upx;

        .inTitle {}

        .introContent {
            font-size: 24upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;

            view {
                padding: 10upx 0
            }

            ;
        }
    }

    .pContent {
        width: 100%;
        height: 80vh;
        background: #fff;
        overflow-y: scroll;

        .pItem {
            box-sizing: border-box;
            padding: 0 20upx;
            margin-bottom: 80upx;

            .pitemImage {
                width: 100%;
            }
        }

        .itemTitle {
            display: flex;
            // margin-bottom: 20upx;
            align-items: center;

            .typeName {
                font-size: 40upx;
                font-family: Hiragino Sans-W5, Hiragino Sans;
                font-weight: normal;
                color: #AAAAAA;
                margin-left: 20upx;
            }
        }

        #title {
            box-sizing: border-box;
            padding: 80upx 0 126upx;
            text-align: center;
            font-size: 40upx;
            font-family: Hiragino Sans-W5, Hiragino Sans;
            font-weight: normal;
            color: rgba(29, 29, 31, 0.9);
        }
    }

    .pTitle {
        height: 112upx;
        background: #FBFBFD;
        border-top-left-radius: 32upx;
        border-top-right-radius: 32upx;
        display: flex;
        align-items: center;
        justify-content: space-between;
        border-bottom: 2upx solid #d2d2d7;
        box-sizing: border-box;
        padding: 0 32upx;

        .pTitlename {
            font-size: 40upx;
            font-family: Hiragino Sans-W5, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
        }

        .pSave {
            font-size: 32upx;
            font-family: Hiragino Sans-W5, Hiragino Sans;
            font-weight: normal;
            color: #1A73E8;
        }

        .pClose {
            width: 60upx;
            height: 60upx;

            image {
                width: 100%;
                height: 100%;
            }
        }
    }

    .itemTitle {
        font-size: 32upx;
        font-family: Hiragino Sans-W6, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
    }

    .itemLeft {
        margin-right: 30upx;
    }

    .items,
    .bk {
        font-size: 32upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        margin-top: 20upx;
    }

    .itemImage {
        width: 550upx;
        height: 328upx;
        background: #FFFFFF;
        box-shadow: 0px 0px 12upx 2upx rgba(0, 0, 0, 0.16);
        margin-top: 40upx;

        image {
            width: 100%;
            height: 100%;
        }
    }

    .listItem {
        display: flex;
        box-sizing: border-box;
        padding: 40upx;
    }

    .bk {
        display: flex;
        align-items: center;
    }

    .colorSqu {
        width: 200upx;
        height: 40upx;
        border-radius: 8upx;
        margin-left: 20upx;
    }

    .u-page {
        padding: 0;
    }

    .u-demo-block__title {
        padding: 10px 0 2px 15px;
    }

    .swipe-action {
        &__content {
            padding: 25rpx 0;

            &__text {
                font-size: 15px;
                color: $u-main-color;
                padding-left: 30rpx;
            }
        }
    }

    .addNew {
        display: flex;
        justify-content: center;
        align-items: center;
        font-size: 40upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1A73E8;
        margin-top: 60upx;
        box-sizing: border-box;
        padding: 40upx 0;
        box-shadow: 0px 8upx 10upx 1upx rgba(0, 0, 0, 0.16);

        text {
            margin-left: 10upx;
        }
    }

    .top1 {
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 60upx 40upx 0;


        .topLeft {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
            margin-right: 36upx;
        }
    }

    .topRight {
        flex: 1;
    }

    .noData {
        width: 100%;
        margin-top: 192upx;
        font-size: 32upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        text-align: center;
    }

    .pickers {
        flex: 1;
        display: flex;
        align-items: center;
        justify-content: space-between;
        width: 100%;
        height: 80upx;
        background: rgba(249, 249, 249, 0.94);
        border-radius: 20upx;
        opacity: 1;
        border: 2upx solid #AAAAAA;
        box-sizing: border-box;
        padding: 0 20upx;

        .pickerName {
            flex: 1;
            text-align: center;
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
        }
    }
</style>
